INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Motivation d''équipes', 'Formation sur les leviers de motivation pour renforcer l’engagement et la performance des équipes.', 4, 250000.00, 'entreprise', '2026-08-05', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre les principaux leviers de motivation\n• Identifier les facteurs individuels et collectifs\n• Mettre en place des stratégies efficaces\n• Développer un style de management adapté\n• Créer un environnement de travail motivant et stimulant\n\n--- OBJECTIFS DÉTAILLÉS ---\nComprendre les leviers de motivation, identifier les facteurs influençant l’engagement, mettre en place des stratégies efficaces, développer un management adapté et créer un environnement de travail stimulant.\n\n--- PRÉREQUIS ---\nExpérience préalable en management ou animation d’équipe souhaitée.\n\n--- CONTENU ---\nModule 1 : Comprendre la motivation en entreprise\nModule 2 : Identifier les leviers de motivation\nModule 3 : Communication et leadership motivant\nModule 4 : Fixation d’objectifs et reconnaissance\nModule 5 : Développement personnel et engagement\nModule 6 : Suivi et évaluation de la motivation\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nManagers, chefs d’équipe, superviseurs, responsables RH et formateurs internes.\n\n--- MÉTHODES ---\nPrésentations interactives, ateliers pratiques, études de cas, simulations, évaluations formatives et feedback personnalisé.\n\n--- SUPPORTS ---\nManuel du participant, fiches pratiques, modèles de plan de motivation, tableaux de suivi, présentations PowerPoint et vidéos pédagogiques.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
